      expect(() => calculateShipping(0, "domestic")).toThrow(ShippingError);
      expect(() => calculateShipping(0, "domestic")).toThrow(
        expect.objectContaining({ code: "INVALID_WEIGHT" })
      );
    });

    it("throws INVALID_WEIGHT for negative weight", () => {
      expect(() => calculateShipping(-5, "domestic")).toThrow(
        expect.objectContaining({ code: "INVALID_WEIGHT" })
      );
    });
  });

  // ── AC2: express_domestic ──────────────────────────────────────────────────
  describe("AC2 – express_domestic", () => {
    it("returns weight * 4.0", () => {
      expect(calculateShipping(10, "express_domestic")).toBe(40);
    });

    it("fractional weight is handled correctly", () => {
      expect(calculateShipping(2.5, "express_domestic")).toBeCloseTo(10);
    });
  });

  // ── AC3: freight ───────────────────────────────────────────────────────────
  describe("AC3 – freight", () => {
    it("returns weight * 1.5", () => {
      expect(calculateShipping(10, "freight")).toBe(15);
    });

    it("is cheaper per kg than domestic", () => {
      const freightCost = calculateShipping(100, "freight");
      const domesticCost = calculateShipping(100, "domestic");
      expect(freightCost).toBeLessThan(domesticCost);
    });
  });

  // ── AC4: unknown destination ───────────────────────────────────────────────
  describe("AC4 – unknown destination", () => {
    it("throws UNKNOWN_DESTINATION for 'mars'", () => {
      expect(() => calculateShipping(10, "mars")).toThrow(ShippingError);
      expect(() => calculateShipping(10, "mars")).toThrow(
        expect.objectContaining({ code: "UNKNOWN_DESTINATION" })
      );
    });

    it("throws UNKNOWN_DESTINATION for empty string", () => {
      expect(() => calculateShipping(10, "")).toThrow(
        expect.objectContaining({ code: "UNKNOWN_DESTINATION" })
      );
    });

    it("throws UNKNOWN_DESTINATION for 'express' (not a valid alias)", () => {
      expect(() => calculateShipping(10, "express")).toThrow(
        expect.objectContaining({ code: "UNKNOWN_DESTINATION" })
      );
    });

    it("UNKNOWN_DESTINATION check runs before INVALID_WEIGHT check", () => {
      // Unknown destination takes priority — no reason to validate weight for an unsupported route
      expect(() => calculateShipping(-1, "mars")).toThrow(
        expect.objectContaining({ code: "UNKNOWN_DESTINATION" })
      );
    });
  });
});

